var body = $json.body || $json;
var requirement = body.requirement || {};
var proposalAnalysis = body.proposalAnalysis || {};
var proposalText = (body.proposalText || '').substring(0, 50000);
var reqStr = JSON.stringify(requirement, null, 2).substring(0, 5000);
var analysisStr = JSON.stringify(proposalAnalysis, null, 2).substring(0, 25000);

var p = 'Ти си одитор на обществени поръчки. Проверяваш дали ТЕХНИЧЕСКОТО предложение на кандидата покрива ЕДНО КОНКРЕТНО ТЕХНИЧЕСКО изискване от документацията на възложителя.

';
p += '## ИЗИСКВАНЕ ЗА ПРОВЕРКА:
' + reqStr + '

';
p += '## СТРУКТУРИРАН АНАЛИЗ НА ТЕХНИЧЕСКОТО ПРЕДЛОЖЕНИЕ НА КАНДИДАТА:
' + analysisStr + '

';
p += '## СУРОВ ТЕКСТ НА ТЕХНИЧЕСКОТО ПРЕДЛОЖЕНИЕ (за верификация):
' + proposalText + '

';
p += '## СТЪПКИ НА ПРОВЕРКА (ИЗПЪЛНИ ВСИЧКИ ПОДРОБНО!):
';
p += '1. НАЛИЧИЕ: Адресирано ли е изискването в техническото предложение? Къде ТОЧНО (секция, страница)?
';
p += '2. ПЪЛНОТА: Покрити ли са ВСИЧКИ подточки/подизисквания? Провери ВСЯКО подизискване поотделно!
';
p += '3. АДЕКВАТНОСТ: Достатъчно конкретен и ДЕТАЙЛЕН ли е отговорът? Или е повърхностен?
';
p += '4. СПЕЦИФИЧНОСТ: Текстът специфичен ли е за ТАЗИ поръчка или е generic шаблонен текст?
';
p += '5. ДОКАЗАТЕЛСТВА: Подкрепено ли е с конкретни доказателства, не само декларативно?
';
p += '6. СЪОТВЕТСТВИЕ: Има ли противоречия с изискванията или вътрешни противоречия?
';
p += '7. ДЪЛБОЧИНА: Описани ли са конкретни стъпки, срокове, отговорници, или само общи фрази?
';
p += '8. ДОБАВЕНА СТОЙНОСТ: Предлага ли кандидатът нещо отвъд минимума?

';
p += '## СТАТУСИ:
';
p += '- COMPLIANT: Покрито НАПЪЛНО, АДЕКВАТНО и ДЕТАЙЛНО — няма какво повече да се изисква
';
p += '- PARTIALLY_COMPLIANT: Адресирано, но с КОНКРЕТНИ пропуски или недостатъчна дълбочина
';
p += '- NON_COMPLIANT: Адресирано, но НЕ отговаря на изискването — съществено несъответствие
';
p += '- MISSING: Изобщо НЕ е адресирано в предложението

';
p += '## КРИТИЧНИ ПРАВИЛА:
';
p += '- Бъди СТРОГ но СПРАВЕДЛИВ — не приемай повърхностен текст за адекватно покритие
';
p += '- НЕ приемай generic текст за валидно покритие на специфично изискване
';
p += '- Цитирай КОНКРЕТЕН текст от предложението (exact quotes)
';
p += '- Цитирай КОНКРЕТЕН текст от изискването
';
p += '- За PARTIALLY/NON_COMPLIANT: обясни подробно КАКВО ТОЧНО липсва или е недостатъчно
';
p += '- За COMPLIANT: обясни ЗАЩО покритието е адекватно
';
p += '- НЕ СЕ ПРОИЗНАСЯЙ по неща извън проверяваното изискване
';
p += '- Бъди ОБЕКТИВЕН — не търси проблеми които съвсем ги няма

';
p += '## ФОРМАТ
';
p += 'Върни САМО валиден JSON (без markdown блокове):
';
p += '{
';
