';
p += '  "analysis": "Подробен анализ 5-10 изречения — с конкретни аргументи и цитати",
';
p += '  "proposal_citations": ["Дословни цитати от предложението"],
';
p += '  "requirement_citations": ["Дословни цитати от изискването"],
';
p += '  "sub_requirement_coverage": [
';
p += '    {
';
p += '      "sub_req_id": "R1.1",
';
p += '      "sub_req_text": "текст",
';
p += '      "covered": true,
';
p += '      "detail_level": "detailed|adequate|superficial|missing",
';
p += '      "notes": "бележки"
';
p += '    }
';
p += '  ],
';
p += '  "deficiencies": [
';
p += '    {
';
p += '      "description": "Подробно описание — КАКВО липсва, ЗАЩО е проблем, КАКВО е необходимо",
';
p += '      "severity": "CRITICAL|MAJOR|MINOR",
';
p += '      "sub_requirement_id": "R1.1 или null"
';
p += '    }
';
p += '  ],
';
p += '  "score": 85,
';
p += '  "notes": "Допълнителни бележки"
';
p += '}';

return [{ json: { prompt: p } }];

var raw = ($json.text || $json.response || '').trim();
var result;

try {
  result = JSON.parse(raw);
} catch (e) {
  var m = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  var candidate = m ? m[1].trim() : raw;
  try {
    var s = candidate.indexOf('{');
    var e2 = candidate.lastIndexOf('}');
    var js = candidate.substring(s, e2 + 1).replace(/,\s*([\]\}])/g, '$1');
    result = JSON.parse(js);
  } catch (e3) {
    result = {
      requirement_id: 'UNKNOWN',
      status: 'COMPLIANT',
      analysis: 'Parse error — defaulting to COMPLIANT to avoid false positives',
      deficiencies: [],
      score: 70,
      _parse_error: true
    };
  }
}

// Validate status
var validStatuses = ['COMPLIANT', 'PARTIALLY_COMPLIANT', 'NON_COMPLIANT', 'MISSING'];
if (validStatuses.indexOf(result.status) === -1) {
  result.status = result.score >= 80 ? 'COMPLIANT' : 'PARTIALLY_COMPLIANT';
}

return [{ json: { finding: result } }];
